create table dirkspzm32.lvs_lgr_cfg (
    sid                      varchar2(2 char) default '01' not null enable,
    firma_nr                 number(2, 0) default 1 not null enable,
    lgr_platz                varchar2(30 char) not null enable,
    lgr_platz_cfg_param      varchar2(40 char) not null enable,
    lgr_platz_cfg_param_wert varchar2(40 char) not null enable,
    created_date             date default sysdate not null enable,
    created_login_id         number(*, 0) default - 1 not null enable,
    last_change_date         date,
    last_change_login_id     number(*, 0)
);

alter table dirkspzm32.lvs_lgr_cfg
    add constraint pk_lvs_lgr_cfg
        primary key ( lgr_platz,
                      lgr_platz_cfg_param,
                      lgr_platz_cfg_param_wert,
                      sid,
                      firma_nr )
            using index enable;


